#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int C[41];
        int total = 0;
        for(int i=0;i<N;i++){
            scanf("%d", &C[i]);
            total += C[i];
        }
        bool dp[206] = {false};
        dp[0] = true;
        for(int i=0;i<N;i++){
            int c = C[i];
            for(int j=total-c; j>=0; --j){
                if(dp[j]) dp[j+c] = true;
            }
        }
        int half = total/2;
        int best = 0;
        for(int s=half; s>=0; --s){
            if(dp[s]){ best = s; break; }
        }
        int ans = (best > total - best) ? best : (total - best);
        printf("%d\n", ans);
    }
    return 0;
}

