#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        C = [int(next(it)) for _ in range(N)]
        total = sum(C)
        dp = [False] * (total + 1)
        dp[0] = True
        for c in C:
            for j in range(total - c, -1, -1):
                if dp[j]:
                    dp[j + c] = True
        half = total // 2
        best = 0
        for s in range(half, -1, -1):
            if dp[s]:
                best = s
                break
        ans = max(best, total - best)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

